-- Crear la tabla de Preguntas Frecuentes
CREATE TABLE IF NOT EXISTS `preguntas_frecuentes` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `pregunta` varchar(255) NOT NULL,
  `respuesta` text NOT NULL,
  `orden` int(11) DEFAULT 0,
  `estado` enum('activo','inactivo') DEFAULT 'activo',
  `fecha_creacion` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Insertar algunas preguntas de ejemplo para tu plataforma
INSERT INTO `preguntas_frecuentes` (`pregunta`, `respuesta`, `orden`, `estado`) VALUES
('¿Qué es PreventWork SG-SST Pro?', 'Es una plataforma tecnológica (SaaS) diseñada para facilitar la administración, control y ejecución del Sistema de Gestión de Seguridad y Salud en el Trabajo bajo la normativa colombiana (Decreto 1072 y Res. 0312).', 1, 'activo'),
('¿Son válidas las firmas digitales recolectadas en la plataforma?', 'Sí. Las firmas recolectadas mediante trazos en pantalla (celular o PC) tienen plena validez jurídica y probatoria bajo la <strong>Ley 527 de 1999</strong> en Colombia.', 2, 'activo'),
('¿Cómo funciona el pago de la suscripción?', 'Todos los pagos se procesan de forma 100% segura a través de la pasarela de pagos <strong>Wompi</strong> (Bancolombia). Puedes elegir facturación mensual o anual según la capacidad de tu empresa.', 3, 'activo'),
('¿Qué pasa si mi empresa supera el límite de trabajadores del plan?', 'Si tu empresa crece y necesitas registrar más trabajadores de los que permite tu plan actual, el sistema te notificará para que realices un <em>upgrade</em> (mejora de plan) pagando únicamente el excedente correspondiente.', 4, 'activo'),
('¿Quién es el dueño de la información que se sube a la plataforma?', 'Tu empresa. Según la Ley 1581 de Habeas Data, la Empresa contratante actúa como <strong>Responsable</strong> de los datos. PreventWork actúa únicamente como proveedor tecnológico (Encargado) asegurando que tus datos estén encriptados y respaldados.', 5, 'activo');